const qs=s=>document.querySelector(s); const detail=qs('#detail'); let regions=[...new Set(curated.map(s=>s.region))].sort(); let osmFeatures=[]; let fishProfiles={}; let activeFish='all'; let userLoc=null; let userMarker=null; let searchMarker=null; let placeSuggestions=[]; let suggestTimer=null; let activeSuggest=-1; const favKey='angelspots:nrw:favorites', notesKey='angelspots:nrw:notes', diaryKey='angelspots:nrw:diary'; function readStore(k,f){try{return JSON.parse(localStorage.getItem(k)||JSON.stringify(f))}catch(e){return f}} function saveStore(k,v){try{localStorage.setItem(k,JSON.stringify(v)); return true}catch(e){alert('Lokales Speichern fehlgeschlagen: Browser-Speicher ist voll oder deaktiviert. Exportiere wichtige Notizen als JSON.'); return false}} function setStoreFlag(k,v){try{localStorage.setItem(k,v); return true}catch(e){return false}} function getStoreFlag(k){try{return localStorage.getItem(k)}catch(e){return null}} let favoriteIds=new Set(readStore(favKey,[])); let spotNotes=readStore(notesKey,{}); let diaryEntries=readStore(diaryKey,[]);
const map=L.map('map').setView([51.43,7.55],8); L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{maxZoom:19,attribution:'© OpenStreetMap'}).addTo(map);
function distKm(a,b,c,d){const R=6371,rad=Math.PI/180; const dLat=(c-a)*rad,dLng=(d-b)*rad; const x=Math.sin(dLat/2)**2+Math.cos(a*rad)*Math.cos(c*rad)*Math.sin(dLng/2)**2; return 2*R*Math.asin(Math.sqrt(x));}
function setLocMsg(t,cls=''){const el=qs('#locMsg'); if(el){el.className='locMsg '+cls; el.textContent=t;}}
function setFocusLocation(lat,lng,label,zoom=11){userLoc={lat,lng,label}; if(searchMarker)map.removeLayer(searchMarker); searchMarker=L.marker([lat,lng],{icon:L.divIcon({className:'',html:'<div class="searchDot"></div>',iconSize:[18,18],iconAnchor:[9,9]})}).addTo(map).bindPopup(esc(label)); map.setView([lat,lng],zoom); setLocMsg('Fokus: '+label+' · Liste nach Entfernung sortiert, wenn sinnvoll.','ok'); render();}
const curatedGroup=L.layerGroup().addTo(map), osmGroup=L.markerClusterGroup({disableClusteringAtZoom:12,chunkedLoading:true,maxClusterRadius:42}).addTo(map); L.control.layers(null,{'Kuratierte Spots':curatedGroup,'OSM-Kandidaten':osmGroup},{position:'topright'}).addTo(map);
function markerHtml(cls,txt){const safeCls=String(cls||'').replace(/[^a-z0-9_-]/gi,''); return L.divIcon({className:'',html:`<div class="marker ${safeCls}">${esc(txt)}</div>`,iconSize:[38,38],iconAnchor:[19,19]})}
function clsForStatus(s){return s==='public'?'m-public':s==='limited'?'m-limited':s==='closed'?'m-closed':'m-unclear'}
function normSource(s){return Array.isArray(s.source)?s.source.join(' ; '):(s.source||'')}
function sourceQuality(s){const src=normSource(s).toLowerCase(); if(/verein|asv|sav|basv|lfv|rheinfischerei|ruhrverband|wupperverband|aggerverband|rurseefischerei|fischerei|angler|angelverein|forellenhof|angelpark|diemelsee|betreiber/.test(src)) return 'operator'; if(/stadt|kreis|gemeinde|lanuv|nabu|naturschutz|verband|wasserverband|tourismus|\.de/.test(src)&&!/openstreetmap|google\.com\/search/.test(src)) return 'publicbody'; return 'directory'}
function qualityLabel(q){return q==='operator'?'Quelle: Betreiber/Verein/Verband':q==='publicbody'?'Quelle: Stadt/Behörde/öffentlich':'Quelle: Verzeichnis/OSM/unklar'}
function practical(s){if(s.status==='closed')return 'nope'; if(s.status==='public')return /rheinerlaubnis|kanalerlaubnis|tages|gast|betreiber|angelpark|erlaubnisschein|karte/i.test(s.legal||'')?'spontan':'karte'; if(s.status==='limited')return /app|gast|tages|karten|erlaubnisschein|lfv|streckenheft/i.test((s.legal||'')+' '+normSource(s))?'karte':'verein'; return 'verein'}
function practicalLabel(p){return p==='spontan'?'Praxis: spontan/planbar':p==='karte'?'Praxis: Karte vorher kaufen':p==='verein'?'Praxis: Verein/Pächter prüfen':'Praxis: nicht angeln'}
function isTopSpot(s){return s.status!=='closed' && s.score>=72 && sourceQuality(s)!=='directory' && ['public','limited'].includes(s.status)}
function isFav(id){return favoriteIds.has(id)}
function saveFavs(){saveStore(favKey,[...favoriteIds]); const el=qs('#sFav'); if(el)el.textContent=favoriteIds.size;}
function toggleFavorite(id){if(favoriteIds.has(id))favoriteIds.delete(id); else favoriteIds.add(id); saveFavs(); render(); const s=curated.find(x=>x.id===id); if(s&&detail.classList.contains('show'))openCurated(s);}
function routeLinks(lat,lng,name='Angelspot'){const dest=encodeURIComponent(lat+','+lng), q=encodeURIComponent(name); return `<div class="actions"><a class="actionBtn" ${relBlank()} href="https://www.google.com/maps/dir/?api=1&destination=${dest}">Google Route</a><a class="actionBtn" ${relBlank()} href="https://maps.apple.com/?daddr=${dest}&q=${q}">Apple Maps</a><a class="actionBtn" ${relBlank()} href="https://www.openstreetmap.org/directions?to=${dest}">OSM Route</a></div>`}
function getFishProfile(name){let p=fishProfiles[name]; if(p&&p.alias)p=fishProfiles[p.alias]; return p||{scientific:'—',image:'https://upload.wikimedia.org/wikipedia/commons/thumb/6/6f/Fish_icon.svg/512px-Fish_icon.svg.png',description:'Zu dieser Fischart ist noch kein Profil hinterlegt. Schonzeit, Mindestmaß und lokale Gewässerordnung bitte vor dem Angeln prüfen.',season:'Nicht hinterlegt – aktuelle NRW- und Gewässerregel prüfen.',minSizeCm:'prüfen',source:'https://recht.nrw.de/'};}
function seasonStatus(season){const m=(season||'').match(/(\d{2})\.(\d{2})\.[–-](\d{2})\.(\d{2})\./); if(!m)return {cls:'',text:'Status: bitte manuell in Erlaubnisschein/Gewässerordnung prüfen.',closed:false,known:false}; const now=new Date(), y=now.getFullYear(); const start=new Date(y,+m[2]-1,+m[1]), end=new Date(y,+m[4]-1,+m[3],23,59,59,999); let closed=end>=start?(now>=start&&now<=end):(now>=start||now<=end); return closed?{cls:'closed',text:'⚠️ Aktuell laut Basisdatum in der Schonzeit – gezieltes Angeln vermeiden und Regeln prüfen.',closed:true,known:true}:{cls:'open',text:'Basisdatum wirkt aktuell außerhalb der Schonzeit – trotzdem Erlaubnisschein/Gewässerordnung prüfen.',closed:false,known:true};}
function esc(s){return String(s??'').replace(/[&<>"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c]))}
function safeUrl(u,allowedHost){try{const url=new URL(String(u||''),location.origin); if(!['http:','https:'].includes(url.protocol))return null; if(allowedHost&&url.hostname!==allowedHost)return null; return url.href}catch(e){return null}}
function safeImageUrl(u){const href=safeUrl(u); return href||'assets/fish-placeholder.svg'}
function relBlank(){return 'target="_blank" rel="noopener noreferrer"'}
function seasonAlertsForSpot(s){return (s.fish||[]).map(name=>{const p=getFishProfile(name), st=seasonStatus(p.season); return {name,p,st}}).filter(x=>x.st.closed)}
function renderSeasonBanner(s){const closed=seasonAlertsForSpot(s); if(closed.length)return `<div class="seasonSpot closed"><b>Schonzeit-Warnung:</b> ${closed.map(x=>esc(x.name)).join(', ')} aktuell laut App-Basisdatum in Schonzeit. Gezielt darauf angeln vermeiden; Gewässerordnung/Erlaubnisschein prüfen.</div>`; const unchecked=(s.fish||[]).filter(f=>!seasonStatus(getFishProfile(f).season).known).slice(0,3); if(unchecked.length)return `<div class="seasonSpot check"><b>Regelcheck:</b> Für ${unchecked.map(esc).join(', ')} ist keine klare NRW-Basis-Schonzeit hinterlegt. Vor Ort unbedingt aktuelle Gewässerordnung prüfen.</div>`; return `<div class="seasonSpot"><b>Schonzeit-Check:</b> Keine hinterlegte Zielfisch-Schonzeit wirkt heute aktiv. Lokale Regeln bleiben maßgeblich.</div>`}
function spotSeasonBadges(s){const closed=seasonAlertsForSpot(s); return closed.length?`<div class="seasonBadges">${closed.slice(0,3).map(x=>`<span class="seasonBadge closed">⚠️ ${esc(x.name)} Schonzeit</span>`).join('')}</div>`:''}
function targetSpecies(s){if(activeFish!=='all'&&(s.fish||[]).includes(activeFish))return activeFish; const open=(s.fish||[]).filter(f=>!seasonStatus(getFishProfile(f).season).closed); return open[0]||(s.fish||[])[0]||'Zielfisch'}
function speciesHint(f,h){const n=(f||'').toLowerCase(); const dusk=h>=19||h<=6; if(/zander|aal|wels/.test(n))return dusk?{bonus:16,text:'Abend/Nacht passt für '+f}:{bonus:-5,text:f+' eher zur Dämmerung/abends einplanen'}; if(/barsch|hecht|forelle|rapfen/.test(n))return (h>=5&&h<=10)||(h>=17&&h<=21)?{bonus:10,text:'Dämmerung/Fressfenster für '+f}:{bonus:0,text:'Tageszeit ok, Dämmerung oft besser'}; if(/karpfen|schleie|barbe|brasse|rotauge|weißfisch|döbel/.test(n))return (h>=9&&h<=19)?{bonus:8,text:'Tagesfenster passt für Friedfisch'}:{bonus:-2,text:'Friedfisch eher tagsüber planbar'}; return {bonus:0,text:'Art-spezifische Zeit heuristisch prüfen'};}
function fishChips(list){return (list||[]).map(f=>`<button type="button" class="fishBtn" data-fish="${esc(f)}">${esc(f)}</button>`).join('')}
function openFishProfile(name){const p=getFishProfile(name), st=seasonStatus(p.season); qs('#fishTitle').textContent=name; qs('#fishSci').textContent=p.scientific||'—'; qs('#fishBody').innerHTML=`<img src="${esc(safeImageUrl(p.image))}" alt="${esc(name)}" loading="lazy" data-fallback="assets/fish-placeholder.svg"><p>${esc(p.description)}</p><div class="seasonBox ${esc(st.cls)}"><b>Schonzeit:</b> ${esc(p.season)}<br><b>Mindestmaß:</b> ${esc(p.minSizeCm)}<br>${esc(st.text)}</div><div class="notice">Konservativer Hinweis: Maßgeblich sind immer aktuelles Landesrecht NRW, Erlaubnisschein, Vereins-/Gewässerordnung, Schonmaße, Entnahmefenster und Beschilderung vor Ort.</div><div class="sourceSmall">Quellen/Bild: ${esc(p.source)}</div>`; qs('#fishModal').classList.add('show');}
function closeFishModal(){qs('#fishModal')?.classList.remove('show')}
function init(){qs('#region').innerHTML+=[...new Set([...regions,...osmFeatures.map(f=>f.properties.region)])].sort().map(r=>`<option>${esc(r)}</option>`).join(''); const wt=qs('#waterType'), me=qs('#method'); if(wt)wt.innerHTML+=[...new Set(curated.map(s=>canonicalWaterType(s.type)).filter(Boolean))].sort((a,b)=>waterTypeLabel(a).localeCompare(waterTypeLabel(b),'de')).map(x=>`<option value="${esc(x)}">${esc(waterTypeLabel(x))}</option>`).join(''); if(me)me.innerHTML+=[...new Set(curated.flatMap(s=>s.methods||[]).map(canonicalMethod).filter(Boolean))].sort((a,b)=>methodLabel(a).localeCompare(methodLabel(b),'de')).map(x=>`<option value="${esc(x)}">${esc(methodLabel(x))}</option>`).join(''); const fishes=[...new Set(curated.flatMap(s=>s.fish||[]))].filter(Boolean).sort(); qs('#chips').innerHTML='<button class="chip active" data-f="all">Alle</button>'+fishes.slice(0,16).map(f=>`<button class="chip" data-f="${esc(f)}">${esc(f)}</button>`).join(''); document.querySelectorAll('.chip').forEach(c=>c.onclick=()=>{document.querySelectorAll('.chip').forEach(x=>x.classList.remove('active'));c.classList.add('active');activeFish=c.dataset.f;render();}); ['q','region','status','quality','practical','waterType','method','minScore','maxDist','sortBy','topOnly','favOnly','notesOnly','diaryOnly'].forEach(id=>{const el=qs('#'+id); if(el) el.oninput=el.onchange=render}); saveFavs(); const place=qs('#placeSearch'); if(place){place.addEventListener('input',()=>debouncedSuggest());place.addEventListener('focus',()=>{if(placeSuggestions.length)renderSuggestions();});place.addEventListener('keydown',handlePlaceKey);} document.addEventListener('click',e=>{if(!e.target.closest('.locbar')&&!e.target.closest('#placeSuggest'))hideSuggestions();}); const pb=qs('#placeBtn'); if(pb)pb.onclick=searchPlace; const gb=qs('#gpsBtn'); if(gb)gb.onclick=useGps; const rb=qs('#resetFilters'); if(rb)rb.onclick=resetFilters; render(); setTimeout(()=>map.invalidateSize(),200)}

function shortPlaceName(r){
  const a=r.address||{}; return a.city||a.town||a.village||a.municipality||a.county||r.name||r.display_name.split(',')[0];
}
function suggestionLabel(r){return r.display_name.split(',').slice(0,5).join(', ')}
function hideSuggestions(){const box=qs('#placeSuggest'); if(box){box.classList.remove('show'); box.innerHTML='';} activeSuggest=-1;}
function renderSuggestions(){
  const box=qs('#placeSuggest'); if(!box) return;
  if(!placeSuggestions.length){hideSuggestions();return;}
  box.innerHTML=placeSuggestions.map((r,i)=>`<button type="button" class="suggestion ${i===activeSuggest?'active':''}" data-i="${i}"><b>${esc(shortPlaceName(r))}</b><span>${esc(suggestionLabel(r))}</span></button>`).join('');
  box.classList.add('show');
  box.querySelectorAll('.suggestion').forEach(btn=>btn.onclick=()=>chooseSuggestion(+btn.dataset.i));
}
async function fetchPlaceSuggestions(q){
  const url='https://nominatim.openstreetmap.org/search?format=json&addressdetails=1&limit=6&countrycodes=de&viewbox=5.7,52.7,9.7,50.2&bounded=0&q='+encodeURIComponent(q+' NRW');
  return fetch(url,{headers:{'Accept':'application/json'}}).then(r=>r.json());
}
function debouncedSuggest(){
  const q=(qs('#placeSearch')?.value||'').trim();
  clearTimeout(suggestTimer);
  if(q.length<2){placeSuggestions=[]; hideSuggestions(); return;}
  suggestTimer=setTimeout(async()=>{
    try{
      const rows=await fetchPlaceSuggestions(q);
      placeSuggestions=rows.filter(r=>r.lat&&r.lon).slice(0,6);
      activeSuggest=placeSuggestions.length?0:-1;
      renderSuggestions();
      setLocMsg(placeSuggestions.length?'Suchvorschläge geladen – antippen zum Reinzoomen.':'Keine Ortsvorschläge gefunden.',''+(placeSuggestions.length?'':'bad'));
    }catch(e){setLocMsg('Suchvorschläge konnten gerade nicht geladen werden.','bad');}
  },280);
}
function handlePlaceKey(e){
  if(e.key==='ArrowDown'&&placeSuggestions.length){e.preventDefault();activeSuggest=(activeSuggest+1)%placeSuggestions.length;renderSuggestions();return;}
  if(e.key==='ArrowUp'&&placeSuggestions.length){e.preventDefault();activeSuggest=(activeSuggest-1+placeSuggestions.length)%placeSuggestions.length;renderSuggestions();return;}
  if(e.key==='Escape'){hideSuggestions();return;}
  if(e.key==='Enter'){e.preventDefault(); if(placeSuggestions.length&&activeSuggest>=0)chooseSuggestion(activeSuggest); else searchPlace();}
}
function chooseSuggestion(i){
  const r=placeSuggestions[i]; if(!r)return;
  const input=qs('#placeSearch'); if(input)input.value=shortPlaceName(r);
  hideSuggestions();
  setFocusLocation(+r.lat,+r.lon,suggestionLabel(r),12);
}
async function searchPlace(){
  const q=(qs('#placeSearch')?.value||'').trim();
  if(!q){setLocMsg('Bitte Ort eingeben, z. B. Hagen, Möhnesee oder Köln.','bad');return;}
  if(placeSuggestions.length){chooseSuggestion(activeSuggest>=0?activeSuggest:0);return;}
  setLocMsg('Suche Ort …');
  try{
    const rows=await fetchPlaceSuggestions(q);
    placeSuggestions=rows.filter(r=>r.lat&&r.lon).slice(0,6);
    if(!placeSuggestions.length){setLocMsg('Ort nicht gefunden. Schreib z. B. „Hagen“, „Möhnesee“ oder „Köln“.','bad');return;}
    if(placeSuggestions.length===1) chooseSuggestion(0); else {activeSuggest=0; renderSuggestions(); setLocMsg('Mehrere Treffer gefunden – bitte Vorschlag antippen.','ok');}
  }catch(e){setLocMsg('Ortssuche konnte gerade nicht geladen werden. Internet/CORS prüfen.','bad');}
}
function useGps(){
  if(!navigator.geolocation){setLocMsg('Dein Browser unterstützt Standortfreigabe hier nicht.','bad');return;}
  setLocMsg('Warte auf Standortfreigabe …');
  navigator.geolocation.getCurrentPosition(pos=>{
    const {latitude:lat,longitude:lng}=pos.coords; userLoc={lat,lng,label:'Aktueller Standort'};
    if(userMarker)map.removeLayer(userMarker);
    userMarker=L.marker([lat,lng],{icon:L.divIcon({className:'',html:'<div class="userDot"></div>',iconSize:[20,20],iconAnchor:[10,10]})}).addTo(map).bindPopup('Aktueller Standort');
    map.setView([lat,lng],12); setLocMsg('Standort aktiv · Liste nach Entfernung sortiert.','ok'); render();
  },err=>setLocMsg('Standort nicht verfügbar oder abgelehnt. Ortssuche funktioniert trotzdem.','bad'),{enableHighAccuracy:true,timeout:10000,maximumAge:60000});
}
function passCurated(s){const q=qs('#q').value.toLowerCase(), r=qs('#region').value, st=qs('#status').value, qu=qs('#quality')?.value||'all', pr=qs('#practical')?.value||'all', wt=qs('#waterType')?.value||'all', me=qs('#method')?.value||'all', min=qs('#minScore')?.value||'all', md=qs('#maxDist')?.value||'all', top=qs('#topOnly')?.checked, fav=qs('#favOnly')?.checked, no=qs('#notesOnly')?.checked, dia=qs('#diaryOnly')?.checked; const hay=[s.name,s.region,s.type,s.legal,s.notes,spotNotes[s.id],normSource(s),...(s.fish||[]),...(s.methods||[])].join(' ').toLowerCase(); const distOk=md==='all'||!userLoc||distKm(userLoc.lat,userLoc.lng,s.lat,s.lng)<=+md; return (!q||hay.includes(q))&&(r==='all'||s.region===r)&&(st==='all'||s.status===st)&&(qu==='all'||sourceQuality(s)===qu)&&(pr==='all'||practical(s)===pr)&&(wt==='all'||canonicalWaterType(s.type)===wt)&&(me==='all'||(s.methods||[]).some(m=>canonicalMethod(m)===me))&&(min==='all'||s.score>=+min)&&distOk&&(!top||isTopSpot(s))&&(!fav||isFav(s.id))&&(!no||!!spotNotes[s.id]?.trim())&&(!dia||diaryForSpot(s.id).length>0)&&(activeFish==='all'||(s.fish||[]).includes(activeFish));}
function passOsm(f){const p=f.properties, q=qs('#q').value.toLowerCase(), r=qs('#region').value, st=qs('#status').value; const extra=(qs('#waterType')?.value||'all')!=='all'||(qs('#method')?.value||'all')!=='all'||(qs('#minScore')?.value||'all')!=='all'||(qs('#maxDist')?.value||'all')!=='all'||qs('#notesOnly')?.checked||qs('#diaryOnly')?.checked; const hay=[p.name,p.kind,p.region,p.priority,JSON.stringify(p.tags||{})].join(' ').toLowerCase(); return !extra&&(!q||hay.includes(q))&&(r==='all'||p.region===r)&&(st==='all'||st==='osm'||st==='unclear')&&(qs('#quality')?.value||'all')==='all'&&(qs('#practical')?.value||'all')==='all'&&!qs('#topOnly')?.checked&&!qs('#favOnly')?.checked&&activeFish==='all';}

function ampel(cls,text){return `<span class="ampel ${cls}">${cls==='green'?'●':cls==='yellow'?'●':'●'} ${text}</span>`}
function trustInfo(s){const q=sourceQuality(s); if(s.status==='closed')return {cls:'red',label:'nicht nutzen',note:'Warn-/Sperrmarker: vor Ort nicht als Angelspot behandeln.'}; if(s.status==='public'&&q==='operator')return {cls:'green',label:'gut belegbar',note:'Quelle wirkt stark; Erlaubnisschein/Gewässerordnung trotzdem prüfen.'}; if(s.status==='public')return {cls:'yellow',label:'belegbar prüfen',note:'Gast-/Öffentlichkeits-Hinweis vorhanden, Details vor Ort gegenprüfen.'}; if(s.status==='limited')return {cls:'yellow',label:'eingeschränkt',note:'Verein/Pächter, Streckenkarte oder Sonderregeln vorher klären.'}; return {cls:'red',label:'unklar',note:'Nur Recherchekandidat/unklare Rechtslage – nicht als Freigabe nutzen.'};}
function ruleRisk(s){if(s.status==='closed')return {cls:'red',label:'hoch',note:'Nicht frei oder stark warnbehaftet.'}; if(s.status==='unclear'||sourceQuality(s)==='directory')return {cls:'red',label:'hoch',note:'Quelle schwach/unklar; erst belastbar recherchieren.'}; if(s.status==='limited'||practical(s)==='verein'||practical(s)==='karte')return {cls:'yellow',label:'mittel',note:'Vorher Karte/Verein/Abschnittsregeln prüfen.'}; return {cls:'green',label:'niedrig-mittel',note:'Trotzdem gelten Schein, Gastkarte, Schonzeiten und Beschilderung.'};}
function permitHint(s){const pr=practical(s); if(s.status==='public')return pr==='karte'?'Gastkarte/Erlaubnis vorher kaufen':'Gast-/öffentlicher Hinweis recherchiert'; if(s.status==='limited')return 'Verein/Pächter/Strecke vorher prüfen'; if(s.status==='closed')return 'nicht als Angelspot nutzen'; return 'unklar – erst Quelle finden';}
function renderQualitySummary(s){const t=trustInfo(s), r=ruleRisk(s), q=sourceQuality(s), pr=practical(s); return `<div class="qualityGrid"><div class="qualityCard"><b>Nutzbarkeit</b>${ampel(t.cls,t.label)}<div class="meta">${t.note}</div></div><div class="qualityCard"><b>Regelrisiko</b>${ampel(r.cls,r.label)}<div class="meta">${r.note}</div></div><div class="qualityCard"><b>Quelle</b>${qualityLabel(q)}<div class="meta">${q==='operator'?'stark':'publicbody'===q?'mittel':'schwach/Verzeichnis'}</div></div><div class="qualityCard"><b>Praxis</b>${practicalLabel(pr)}<div class="meta">${permitHint(s)}</div></div></div>`}
function renderPracticeCards(s){const methods=(s.methods||[]).join(', ')||'vor Ort/Ordnung prüfen'; const fish=(s.fish||[]).slice(0,8).join(', ')||'nicht hinterlegt'; const src=sourceLinks(s); return `<div class="infoGrid"><div class="infoCard"><b>Darf ich hier angeln?</b>${esc(s.legal||permitHint(s))}</div><div class="infoCard"><b>Wo Karte/Quelle prüfen?</b>${src}</div><div class="infoCard"><b>Zielfische</b>${esc(fish)}</div><div class="infoCard"><b>Methoden</b>${esc(methods)}</div><div class="infoCard wide"><b>Risiken / Praxisnotiz</b>${esc(s.notes||ruleRisk(s).note)}</div></div>`}
function diaryStats(id){const d=diaryForSpot(id); const last=d[0]?.date||'—'; const fish=d.filter(e=>e.fish).reduce((m,e)=>(m[e.fish]=(m[e.fish]||0)+1,m),{}); const top=Object.entries(fish).sort((a,b)=>b[1]-a[1])[0]?.[0]||'—'; return {count:d.length,last,top}}
function render(){curatedGroup.clearLayers(); osmGroup.clearLayers(); const a=curated.filter(passCurated).sort(compareSpots); a.forEach(s=>L.marker([s.lat,s.lng],{icon:markerHtml(clsForStatus(s.status),isFav(s.id)?'★':(s.status==='closed'?'!':s.score))}).on('click',()=>openCurated(s)).addTo(curatedGroup)); const fo=osmFeatures.filter(passOsm); const rs=qs('#resultSummary'); if(rs)rs.textContent=`${a.length} kuratierte Spots${fo.length?' · '+fo.length+' OSM-Kandidaten':''} · Sortierung: ${qs('#sortBy')?.selectedOptions?.[0]?.textContent?.replace('Sortierung: ','')||'smart'}`; fo.forEach(f=>{const p=f.properties; const [lng,lat]=f.geometry.coordinates; osmGroup.addLayer(L.marker([lat,lng],{icon:markerHtml('m-osm-'+esc(p.priority),esc(p.priority))}).on('click',()=>openOsm(f)));}); qs('#list').innerHTML=a.slice(0,90).map(s=>{const q=sourceQuality(s), pr=practical(s), fav=isFav(s.id), t=trustInfo(s), r=ruleRisk(s); return `<article class="spot" data-open-id="${esc(s.id)}"><div class="spotTop"><div><h3>${fav?'★ ':''}${esc(s.name)}</h3><div class="meta">${esc(s.region)} · ${esc(s.type)}${userLoc?' · '+distKm(userLoc.lat,userLoc.lng,s.lat,s.lng).toFixed(1)+' km vom Fokus':''}</div></div><div class="score">${s.status==='closed'?'!':esc(s.score)}</div></div><div class="pills"><span class="pill ${esc(s.status)}">${label(s.status)}</span><span class="pill">${esc((s.fish||[]).slice(0,3).join(', '))}</span></div><div class="minirow"><span class="qbadge q-${esc(q)}">${qualityLabel(q)}</span><span class="qbadge p-${esc(pr)}">${practicalLabel(pr)}</span>${isTopSpot(s)?'<span class="qbadge q-operator">Top-Spot</span>':''}<span class="qbadge">${esc(t.label)}</span><span class="qbadge">Risiko ${esc(r.label)}</span>${localBadges(s)}</div>${spotSeasonBadges(s)}<div class="actions"><button type="button" class="favBtn ${fav?'active':''}" data-fav-id="${esc(s.id)}">${fav?'★ Gespeichert':'☆ Merken'}</button><a class="actionBtn" ${relBlank()} href="https://www.google.com/maps/dir/?api=1&destination=${encodeURIComponent(s.lat+','+s.lng)}">Route</a></div></article>`}).join('') + `<div class="notice">${a.length} kuratierte Treffer · ${favoriteIds.size} Favoriten gespeichert. OSM-Kandidaten im aktuellen Filter: ${fo.length}. Diese erscheinen als Cluster/Marker auf der Karte und dienen als Recherche-Layer.</div>`; qs('#sOsm').textContent=osmFeatures.length; const sf=qs('#sFav'); if(sf)sf.textContent=favoriteIds.size;}
function label(s){return s==='public'?'Gast-/öffentlich belegbar':s==='limited'?'Verein/prüfen':s==='closed'?'nicht frei':'unklar'}
function canonicalWaterType(t){const x=String(t||'').toLowerCase(); if(/rhein|ruhr|rur|lippe|weser|ems|sieg|fluss|bach|mündung|kanalfluss/.test(x))return 'river'; if(/kanal/.test(x))return 'canal'; if(/talsperre|stausee|rückhalte/.test(x))return 'reservoir'; if(/forell|angelpark|anlage|hof|zucht|kommerziell/.test(x))return 'commercial'; if(/bagger|kies|see|weiher|teich|bruch|altarm|seenplatte|moor|ville|restsee/.test(x))return 'lake'; if(/nsg|schutz|trinkwasser|false/.test(x))return 'restricted'; if(/poi|heim|vereins/.test(x))return 'poi'; return 'other'}
function waterTypeLabel(k){return ({river:'Fluss/Bach',canal:'Kanal',reservoir:'Stau-/Talsperre',lake:'See/Teich/Baggersee',commercial:'Forellenhof/Angelpark',restricted:'Schutzgebiet/unklar',poi:'POI/Vereinshinweis',other:'Sonstige'})[k]||k}
function canonicalMethod(m){const x=String(m||'').toLowerCase(); if(/spinn|drop shot|sbirolino/.test(x))return 'spinning'; if(/ansitz|grund|naturköder|pose|posen/.test(x))return 'bait'; if(/feed/.test(x))return 'feeder'; if(/karpfen|friedfisch/.test(x))return 'coarse'; if(/forell/.test(x))return 'trout'; if(/boot|schlepp/.test(x))return 'boat'; if(/fliegen/.test(x))return 'fly'; return 'other'}
function methodLabel(k){return ({spinning:'Spinnfischen/aktive Köder',bait:'Ansitz/Grund/Pose',feeder:'Feedern',coarse:'Karpfen/Friedfisch',trout:'Forellenangeln',boat:'Boot/Schleppen',fly:'Fliegenfischen',other:'Sonstige'})[k]||k}
function riskRank(s){const r=ruleRisk(s).cls; return r==='green'?0:r==='yellow'?1:2}
function compareSpots(x,y){const mode=qs('#sortBy')?.value||'smart'; if(mode==='distance'&&userLoc)return distKm(userLoc.lat,userLoc.lng,x.lat,x.lng)-distKm(userLoc.lat,userLoc.lng,y.lat,y.lng); if(mode==='score')return y.score-x.score; if(mode==='risk')return riskRank(x)-riskRank(y)||y.score-x.score; if(mode==='name')return x.name.localeCompare(y.name,'de'); if(userLoc)return distKm(userLoc.lat,userLoc.lng,x.lat,x.lng)-distKm(userLoc.lat,userLoc.lng,y.lat,y.lng); return y.score-x.score}
function resetFilters(){['q','placeSearch'].forEach(id=>{const el=qs('#'+id); if(el)el.value=''}); ['region','status','quality','practical','waterType','method','minScore','maxDist','sortBy'].forEach(id=>{const el=qs('#'+id); if(el)el.value=id==='sortBy'?'smart':'all'}); ['topOnly','favOnly','notesOnly','diaryOnly'].forEach(id=>{const el=qs('#'+id); if(el)el.checked=false}); activeFish='all'; document.querySelectorAll('.chip').forEach(c=>c.classList.toggle('active',c.dataset.f==='all')); placeSuggestions=[]; hideSuggestions(); setLocMsg('Filter zurückgesetzt. Ortssuche/Standort kannst du danach neu setzen.','ok'); render()}
window.openById=id=>openCurated(curated.find(s=>s.id===id)); window.toggleFavorite=toggleFavorite; window.openFishProfile=openFishProfile; window.closeFishModal=closeFishModal; window.saveSpotNote=saveSpotNote; window.addDiaryEntry=addDiaryEntry; window.deleteDiaryEntry=deleteDiaryEntry; window.exportDiary=exportDiary; window.importDiaryFile=importDiaryFile;
function sourceLinks(s){return normSource(s).split(/\s*;\s*/).filter(Boolean).map((u,i)=>{const href=safeUrl(u); return href?`<a ${relBlank()} href="${esc(href)}">Quelle ${i+1}</a>`:`<span>${esc(u)}</span>`}).join(' · ')||'Quelle noch nachpflegen'}
function saveNotes(){return saveStore(notesKey,spotNotes)}
function saveDiary(){return saveStore(diaryKey,diaryEntries)}
function diaryForSpot(id){return diaryEntries.filter(e=>e.spotId===id).sort((a,b)=>String(b.date||b.createdAt).localeCompare(String(a.date||a.createdAt)))}
function localBadges(s){const n=spotNotes[s.id]?.trim(), d=diaryForSpot(s.id).length; return `${n?'<span class="qbadge localMini">📝 Notiz</span>':''}${d?`<span class="qbadge localMini">🎣 ${d} Eintrag${d>1?'e':''}</span>`:''}`}
function renderDiaryEntries(id){const list=diaryForSpot(id).slice(0,6); if(!list.length)return '<div class="meta">Noch keine Fänge/Besuche für diesen Spot gespeichert.</div>'; return `<div class="diaryList">${list.map(e=>`<div class="diaryEntry"><button type="button" data-delete-entry="${esc(e.id)}" data-spot-id="${esc(id)}">löschen</button><b>${esc(e.date||'ohne Datum')}</b> · ${esc(e.fish||'Fisch?')} ${e.lengthCm?`· ${esc(e.lengthCm)} cm`:''}${e.weightG?` · ${esc(e.weightG)} g`:''}<br><span class="meta">${esc(e.method||'Methode?')}${e.weather?' · '+esc(e.weather):''}</span>${e.text?`<br>${esc(e.text)}`:''}</div>`).join('')}</div>`}
function renderLocalPanel(s){const entries=renderDiaryEntries(s.id), fishOpts=(s.fish||[]).map(f=>`<option>${esc(f)}</option>`).join(''), methodOpts=(s.methods||[]).map(m=>`<option>${esc(m)}</option>`).join(''), today=new Date().toISOString().slice(0,10), st=diaryStats(s.id); return `<section class="localPanel"><h3>Meine Notizen & Fangtagebuch</h3><p class="meta">Bleibt privat und lokal auf diesem Gerät gespeichert.</p><div class="localStats"><div class="localStat"><b>${st.count}</b><span>Einträge</span></div><div class="localStat"><b>${esc(st.last).slice(5)||'—'}</b><span>letzter Besuch</span></div><div class="localStat"><b>${esc(st.top)}</b><span>Top-Fisch</span></div></div><textarea id="note_${esc(s.id)}" placeholder="Eigene Notiz: Parken, Uferstelle, Köder, Regeln …">${esc(spotNotes[s.id]||'')}</textarea><div class="actions"><button type="button" class="favBtn" data-note-id="${esc(s.id)}">Notiz speichern</button><button type="button" class="favBtn" data-action="export-diary">Export JSON</button><label class="favBtn" for="diaryImport_${esc(s.id)}">Import JSON</label><input id="diaryImport_${esc(s.id)}" class="hiddenFile" type="file" accept="application/json" data-import-diary></div><div class="diaryForm"><input id="diaryDate_${esc(s.id)}" type="date" value="${today}"><select id="diaryFish_${esc(s.id)}"><option value="">Fischart</option>${fishOpts}</select><select id="diaryMethod_${esc(s.id)}"><option value="">Methode</option>${methodOpts}</select><input id="diaryLen_${esc(s.id)}" inputmode="decimal" placeholder="Länge cm"><input id="diaryWeight_${esc(s.id)}" inputmode="decimal" placeholder="Gewicht g"><input id="diaryWeather_${esc(s.id)}" placeholder="Wetter/Phase"><textarea class="wide" id="diaryText_${esc(s.id)}" placeholder="Kurze Fang-/Besuchsnotiz"></textarea></div><button type="button" class="favBtn exportBtn" data-add-diary="${esc(s.id)}">Fang/Besuch speichern</button><h3>Letzte Einträge</h3>${entries}</section>`}
function saveSpotNote(id){const el=document.getElementById('note_'+id); if(!el)return; const v=el.value.trim(); if(v)spotNotes[id]=v; else delete spotNotes[id]; saveNotes(); render(); const s=curated.find(x=>x.id===id); if(s)openCurated(s)}
function addDiaryEntry(id){const g=n=>document.getElementById(n+'_'+id)?.value?.trim()||''; const entry={id:'d'+Date.now(),spotId:id,date:g('diaryDate'),fish:g('diaryFish'),method:g('diaryMethod'),lengthCm:g('diaryLen'),weightG:g('diaryWeight'),weather:g('diaryWeather'),text:g('diaryText'),createdAt:new Date().toISOString()}; diaryEntries.push(entry); saveDiary(); render(); const s=curated.find(x=>x.id===id); if(s)openCurated(s)}
function deleteDiaryEntry(entryId,spotId){diaryEntries=diaryEntries.filter(e=>e.id!==entryId); saveDiary(); render(); const s=curated.find(x=>x.id===spotId); if(s)openCurated(s)}
function exportDiary(){const data=JSON.stringify({notes:spotNotes,diary:diaryEntries,exportedAt:new Date().toISOString()},null,2); const a=document.createElement('a'); a.href=URL.createObjectURL(new Blob([data],{type:'application/json'})); a.download='angelspots-tagebuch.json'; a.click(); setTimeout(()=>URL.revokeObjectURL(a.href),1000)}
function cleanText(v,max=500){return String(v??'').slice(0,max)}
function cleanDiaryEntry(e){if(!e||typeof e!=='object'||!e.spotId)return null; return {id:/^[a-zA-Z0-9_-]{1,64}$/.test(String(e.id||''))?String(e.id):'d'+Date.now()+Math.random().toString(36).slice(2,8),spotId:cleanText(e.spotId,80),date:cleanText(e.date,20),fish:cleanText(e.fish,80),method:cleanText(e.method,80),lengthCm:cleanText(e.lengthCm,20),weightG:cleanText(e.weightG,20),weather:cleanText(e.weather,120),text:cleanText(e.text,1000),createdAt:cleanText(e.createdAt||new Date().toISOString(),40)}}
function importDiaryFile(input){const file=input.files?.[0]; if(!file)return; if(file.size>512000){alert('Import abgebrochen: Datei ist größer als 500 KB.');return;} const reader=new FileReader(); reader.onload=()=>{try{const data=JSON.parse(reader.result); if(data.notes&&typeof data.notes==='object'){Object.entries(data.notes).slice(0,500).forEach(([k,v])=>{spotNotes[cleanText(k,80)]=cleanText(v,2000)})} if(Array.isArray(data.diary)){const rows=data.diary.slice(0,500).map(cleanDiaryEntry).filter(Boolean); diaryEntries=[...diaryEntries,...rows].slice(-1000)} saveNotes(); saveDiary(); render(); alert('Import erledigt.');}catch(e){alert('Import fehlgeschlagen: ungültige JSON-Datei.')}}; reader.readAsText(file)}
function openCurated(s){map.setView([s.lat,s.lng],11); detail.classList.add('show'); const q=sourceQuality(s), pr=practical(s), fav=isFav(s.id); qs('#detailBody').innerHTML=`<div class="eyebrow">kuratierter NRW-Spot</div><h2>${esc(s.name)}</h2><div class="meta">${esc(s.region)} · ${esc(s.type)}${userLoc?' · '+distKm(userLoc.lat,userLoc.lng,s.lat,s.lng).toFixed(1)+' km vom Fokus':''}</div><div class="pills"><span class="pill ${esc(s.status)}">${label(s.status)}</span><span class="pill">Score ${esc(s.score)}</span><span class="pill">${isTopSpot(s)?'Top-Spot':'normal'}</span></div><div class="minirow"><span class="qbadge q-${esc(q)}">${qualityLabel(q)}</span><span class="qbadge p-${esc(pr)}">${practicalLabel(pr)}</span>${localBadges(s)}</div>${renderQualitySummary(s)}${spotSeasonBadges(s)}<div class="actions"><button type="button" class="favBtn ${fav?'active':''}" data-fav-id="${esc(s.id)}">${fav?'★ In Merkliste':'☆ Zur Merkliste'}</button></div><div class="favHint">Favoriten bleiben lokal auf diesem Gerät gespeichert.</div>${renderSeasonBanner(s)}<div class="fish">${fishChips(s.fish)}</div><div class="live" id="live">Live-Wetter wird geladen …</div><div id="weekPlan"></div><div id="pegelBox"></div><h3>Praxis-Check</h3>${renderPracticeCards(s)}${renderLocalPanel(s)}${routeLinks(s.lat,s.lng,s.name)}<div class="notice">Vor Ort gilt immer die offizielle Vereins-/Gewässerkarte. Diese Seite ist Recherchehilfe, keine Rechtsfreigabe.</div>`; loadLive(s); loadPegel(s);}
function openOsm(f){const p=f.properties,[lng,lat]=f.geometry.coordinates; const osm=safeUrl(p.osm_url,'www.openstreetmap.org'); map.setView([lat,lng],12); detail.classList.add('show'); qs('#detailBody').innerHTML=`<div class="eyebrow">OSM-Recherchekandidat · keine Freigabe</div><h2>${esc(p.name)}</h2><div class="meta">${esc(p.region)} · ${esc(p.kind)}</div><div class="pills"><span class="pill unclear">Priorität ${esc(p.priority)} / ${esc(p.priority_score)}</span><span class="pill unclear">Status unklar</span></div><p>Dieser Punkt kommt aus OpenStreetMap/Overpass. Er ist ein Kandidat für weitere Recherche, kein bestätigter Angelspot.</p><p>${osm?`<a ${relBlank()} href="${esc(osm)}">OSM öffnen</a>`:'OSM-Link nicht validiert'}</p>${routeLinks(lat,lng,p.name)}<pre class="osmTags">${esc(JSON.stringify(p.tags,null,2))}</pre>`;}
function wmoText(c){return ({0:'klar',1:'meist klar',2:'teilweise bewölkt',3:'bewölkt',45:'Nebel',48:'Reifnebel',51:'Niesel',53:'Niesel',55:'starker Niesel',61:'Regen',63:'Regen',65:'starker Regen',71:'Schnee',80:'Schauer',81:'Schauer',82:'starke Schauer',95:'Gewitter',96:'Gewitter/Hagel',99:'Gewitter/Hagel'})[c]||'wechselhaft'}
function hourScore(s,h,i,target){const hour=+h.time[i].slice(11,13), temp=h.temperature_2m[i], wind=h.wind_speed_10m[i], gust=h.wind_gusts_10m?.[i]||wind, code=h.weather_code[i], rain=h.precipitation_probability[i]??0, cloud=h.cloud_cover?.[i]??50, pressure=h.pressure_msl?.[i]??1013, p3=h.pressure_msl?.[Math.max(0,i-3)]??pressure, trend=pressure-p3; let sc=58; if(temp>=8&&temp<=22)sc+=10; else if(temp<3||temp>28)sc-=10; if(wind<18)sc+=12; else if(wind>35||gust>55)sc-=22; if(cloud>35&&cloud<90)sc+=5; if(pressure>=1005&&pressure<=1022)sc+=4; if(trend>-2&&trend<4)sc+=4; else if(trend<=-5)sc-=8; if([2,3,61,63,80].includes(code))sc+=4; if([95,96,99,65,82].includes(code))sc-=32; if(rain>60)sc-=10; const sh=speciesHint(target,hour); sc+=sh.bonus; if(s.status==='closed')sc=15; if(s.status==='unclear')sc-=12; if(seasonAlertsForSpot(s).some(x=>x.name===target))sc=15; return {score:Math.max(10,Math.min(96,Math.round(sc))),hint:sh.text,hour,temp,wind,gust,code,rain,cloud,pressure,trend,time:h.time[i]};}
function renderWeek(d,s){try{const h=d.hourly, days={}, target=targetSpecies(s); h.time.forEach((t,i)=>{const hour=+t.slice(11,13); if(hour<5||hour>23)return; const slot=hourScore(s,h,i,target); const day=t.slice(0,10); if(!days[day]||slot.score>days[day].score)days[day]=slot;}); const rows=Object.entries(days).slice(0,7).map(([day,x])=>`<div class="day"><b>${day.slice(8)}.${day.slice(5,7)}</b><div><div>${x.time.slice(11,16)} · ${wmoText(x.code)} · ${Math.round(x.temp)}°C · ${Math.round(x.wind)} km/h · ${esc(target)}</div><div class="bar"><i data-score="${x.score}"></i></div></div><b>${x.score}</b></div>`).join(''); qs('#weekPlan').innerHTML=`<h3>7-Tage-Planer für ${esc(target)}</h3><div class="planner">${rows}</div>`; qs('#weekPlan').querySelectorAll('.bar i[data-score]').forEach(el=>{el.style.width=Math.max(0,Math.min(100,+el.dataset.score||0))+'%'})}catch(e){}}
function bestForDate(d,s,date){const h=d.hourly, target=targetSpecies(s); let best=null; h.time.forEach((t,i)=>{if(!t.startsWith(date))return; const hour=+t.slice(11,13); if(hour<5||hour>23)return; const slot=hourScore(s,h,i,target); if(!best||slot.score>best.score)best=slot;}); return {best,target};}
function bestToday(d,s){const today=(d.current?.time||new Date().toISOString()).slice(0,10); return bestForDate(d,s,today)}
function pegelStation(s){const hay=(s.name+' '+s.region+' '+s.type+' '+(s.legal||'')).toLowerCase(); if(hay.includes('rhein'))return 'DUISBURG-RUHRORT'; if(hay.includes('ruhr')||hay.includes('baldeney')||hay.includes('harkort')||hay.includes('hengstey')||hay.includes('kemnader'))return 'HATTINGEN'; if(hay.includes('lippe'))return 'Wesel'; if(hay.includes('weser'))return 'MINDEN'; if(hay.includes('ems'))return 'RHEINE'; if(hay.includes('sieg'))return 'BETZDORF'; if(hay.includes('rur'))return 'DUEREN'; return null}
async function loadPegel(s){const box=qs('#pegelBox'), st=pegelStation(s); if(!box||!st){if(box)box.innerHTML='<div class="pegel">Pegel: für dieses Gewässer noch keine passende automatische Station hinterlegt.</div>'; return} try{const stations=await fetch(`https://www.pegelonline.wsv.de/webservices/rest-api/v2/stations.json?includeTimeseries=true`).then(r=>r.json()); const station=stations.find(x=>(x.longname||x.shortname||'').toUpperCase().includes(st.toUpperCase())); if(!station){box.innerHTML=`<div class="pegel">Pegel: Station ${st} nicht gefunden.</div>`;return} const ts=(station.timeseries||[]).find(t=>t.shortname==='W'||t.longname?.toLowerCase().includes('wasserstand')); const cur=ts?.currentMeasurement; box.innerHTML=`<div class="pegel"><b>Pegel-Näherung:</b> ${station.longname||station.shortname}${cur?` · ${cur.value} ${ts.unit||''}`:''}<br><span class="meta">PEGELONLINE/WSV · nur Näherung, nicht automatische Angel-Freigabe.</span></div>`}catch(e){box.innerHTML='<div class="pegel">Pegel konnte gerade nicht geladen werden.</div>'}}
async function loadLive(s){try{const url=`https://api.open-meteo.com/v1/forecast?latitude=${s.lat}&longitude=${s.lng}&timezone=Europe%2FBerlin&current=temperature_2m,precipitation,wind_speed_10m,wind_gusts_10m,pressure_msl,cloud_cover,weather_code&hourly=temperature_2m,precipitation_probability,wind_speed_10m,wind_gusts_10m,pressure_msl,cloud_cover,weather_code&daily=sunrise,sunset&forecast_days=7`; const d=await fetch(url).then(r=>r.json()); const c=d.current; let risk=[]; if(c.wind_gusts_10m>55||c.wind_speed_10m>40)risk.push('Sturm/Starkwind'); if([95,96,99].includes(c.weather_code))risk.push('Gewitter'); if(c.precipitation>3)risk.push('starker Regen'); const bt=bestToday(d,s), b=bt.best, tomorrow=d.daily?.time?.[1]?bestForDate(d,s,d.daily.time[1]):{best:null,target:bt.target}, closed=seasonAlertsForSpot(s); const score=b?b.score:Math.max(20,Math.min(98,70+(c.wind_speed_10m<25?8:-15)+(c.cloud_cover>35?5:0)-(risk.length*22))); const tips=[]; if(b)tips.push(`<div class="tip good"><b>Beste Zeit heute:</b> ${b.time.slice(11,16)} Uhr für ${esc(bt.target)} · ${esc(b.hint)} · Luftdrucktrend ${b.trend>0?'+':''}${Math.round(b.trend)} hPa/3h</div>`); if(tomorrow.best)tips.push(`<div class="tip next"><b>Morgen:</b> ${tomorrow.best.time.slice(11,16)} Uhr · Score ${tomorrow.best.score}/100</div>`); if(closed.length)tips.push(`<div class="tip warn"><b>Schonzeit:</b> ${closed.map(x=>esc(x.name)).join(', ')} nicht gezielt befischen.</div>`); if(risk.length)tips.push(`<div class="tip warn"><b>Sicherheit:</b> ${risk.join(' · ')} – geschütztes Ufer/Pause prüfen.</div>`); qs('#live').innerHTML=`<b>Heute angeln? ${Math.round(score)}/100</b><div class="weather"><span>🎯 ${esc(bt.target)}</span><span>🌡️ ${Math.round(c.temperature_2m)} °C</span><span>💨 ${Math.round(c.wind_speed_10m)} km/h</span><span>🌬️ Böen ${Math.round(c.wind_gusts_10m)} km/h</span><span>🔽 ${Math.round(c.pressure_msl)} hPa</span></div><div class="todayTips">${tips.join('')||'<div class="tip good"><b>Okay:</b> Keine grobe Sturm-/Gewitterlage aus Live-Daten.</div>'}</div><p class="meta">Open-Meteo 7 Tage · Zielfisch-Heuristik · keine Rechts-/Fanggarantie.</p>`; renderWeek(d,s);}catch(e){qs('#live').textContent='Live-Wetter konnte gerade nicht geladen werden.'}}

let deferredInstall=null;
window.addEventListener('beforeinstallprompt',e=>{e.preventDefault(); deferredInstall=e; const h=qs('#pwaHint'); if(h&&!getStoreFlag('angelspots:pwa:dismiss'))h.classList.add('show')});
function initPwaHint(){const b=qs('#installBtn'), d=qs('#dismissPwa'); if(b)b.onclick=async()=>{if(deferredInstall){deferredInstall.prompt(); await deferredInstall.userChoice; deferredInstall=null;} qs('#pwaHint')?.classList.remove('show')}; if(d)d.onclick=()=>{setStoreFlag('angelspots:pwa:dismiss','1'); qs('#pwaHint')?.classList.remove('show')}}
function setSwStatus(text){const el=qs('#swStatus'); if(el)el.innerHTML='<b>Offline:</b> '+text;}
function initSafeEventDelegation(){
  document.addEventListener('click',e=>{
    const t=e.target;
    if(t.closest('[data-action="close-detail"]')){detail.classList.remove('show');return;}
    if(t.closest('[data-action="close-fish"]')||(t.id==='fishModal')){closeFishModal();return;}
    const fav=t.closest('[data-fav-id]'); if(fav){e.preventDefault(); e.stopPropagation(); toggleFavorite(fav.dataset.favId); return;}
    const fish=t.closest('[data-fish]'); if(fish){e.preventDefault(); openFishProfile(fish.dataset.fish); return;}
    const del=t.closest('[data-delete-entry]'); if(del){e.preventDefault(); deleteDiaryEntry(del.dataset.deleteEntry,del.dataset.spotId); return;}
    const note=t.closest('[data-note-id]'); if(note){e.preventDefault(); saveSpotNote(note.dataset.noteId); return;}
    if(t.closest('[data-action="export-diary"]')){e.preventDefault(); exportDiary(); return;}
    const add=t.closest('[data-add-diary]'); if(add){e.preventDefault(); addDiaryEntry(add.dataset.addDiary); return;}
    if(t.closest('.spot .actionBtn')){e.stopPropagation(); return;}
    const spot=t.closest('[data-open-id]'); if(spot){openById(spot.dataset.openId); return;}
  });
  document.addEventListener('change',e=>{if(e.target.matches('[data-import-diary]'))importDiaryFile(e.target)});
  document.addEventListener('error',e=>{const img=e.target; if(img&&img.matches&&img.matches('img[data-fallback]')){img.removeAttribute('data-fallback'); img.src='assets/fish-placeholder.svg';}},true);
}
function registerOfflineCache(){if(!('serviceWorker' in navigator)){setSwStatus('nicht unterstützt');return;} navigator.serviceWorker.register('/sw.js').then(reg=>{setSwStatus('bereit – Karte, Spots, Favoriten/Notizen lokal nutzbar'); if(reg.waiting)reg.waiting.postMessage({type:'SKIP_WAITING'});}).catch(()=>setSwStatus('Cache konnte nicht aktiviert werden'));}
async function boot(){
  try{
    const files=['hagen_local_spots.json','nrw_curated_ruhrgebiet.json','nrw_curated_niederrhein_duesseldorf.json','nrw_curated_rheinland_koeln_bonn.json','nrw_curated_aachen_eifel.json','nrw_curated_muensterland.json','nrw_curated_owl.json','nrw_curated_sauerland_siegerland_bergisches.json','nrw_curated_round2_west_rheinland.json','nrw_curated_round2_eifel_muensterland.json','nrw_curated_round2_owl_sauerland.json','nrw_curated_round3_quality.json','nrw_curated_round5_osm_triage.json','nrw_curated_round6_regional_deepening.json'];
    const [geo, profiles, ...packs]=await Promise.all([
      fetch('data/nrw_angelspot_candidates.geojson').then(r=>r.json()).catch(()=>({features:[]})),
      fetch('data/fish_profiles.json').then(r=>r.json()).catch(()=>({})),
      ...files.map(f=>fetch('data/'+f).then(r=>r.json()).catch(()=>([])))
    ]);
    osmFeatures=geo.features||[]; fishProfiles=profiles||{};
    const seen=new Set(curated.map(s=>(s.name||'').toLowerCase().replace(/\s+/g,' ').trim()));
    for(const pack of packs){for(const s of pack){const k=(s.name||'').toLowerCase().replace(/\s+/g,' ').trim(); if(!seen.has(k)){curated.push(s); seen.add(k);}}}
    regions=[...new Set(curated.map(s=>s.region))].sort();
    qs('#sCur').textContent=curated.length;
  }catch(e){osmFeatures=[];}
  init(); initPwaHint(); initSafeEventDelegation(); registerOfflineCache();
}
boot();
